+function defaultHeadingDisplay(target: string): string | null {
+  const hashIndex = target.indexOf('#');
+  if (hashIndex === -1 || hashIndex === target.length - 1) {
+    return null;
+  }
+  const page = target.slice(0, hashIndex);
+  const heading = target.slice(hashIndex + 1);
+  return page ? `${page} > ${heading}` : heading;
+}
+
+function wikiToMarkdown(text: string, convertLinks: boolean, convertImages: boolean): string {
+  return text.replace(/(!?)\\\\[\\\\[([^\\]\
|]+)(?:\\\\|([^\\]\
|]+))?\\\\]\\\\]/g, (match, bang: string, target: string, display?: string) => {
+    const image = bang === '!';
+    if ((image && !convertImages) || (!image && !convertLinks)) {
+      return match;
+    }
+
+    if (image) {
+      const alt = display === '300' || display === '300x200' ? target : (display ?? target);
+      return `![${alt}](${target})`;
+    }
+
+    const label = display ?? defaultHeadingDisplay(target) ?? target;
+    return `[${label}](${target})`;
+  });
+}
