+/** Parse the deliberately limited inline Markdown link grammar supported by this rule. */
+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  const image = text[start] === '!';
+  const labelStart = start + (image ? 2 : 1);
+  let index = labelStart;
+  let depth = 0;
+  for (; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === '[') {
+      depth++;
+    } else if (text[index] === ']') {
+      if (depth === 0) break;
+      depth--;
+    }
+  }
+  if (index >= text.length || text[index + 1] !== '(') return null;
+
+  const label = text.slice(labelStart, index);
+  const contentStart = index + 2;
+  let end: number;
+  let target: string;
+
+  if (text[contentStart] === '<' || (/^[ \	]/).test(text[contentStart] ?? '') && text.slice(contentStart).match(/^[ \	]*</)) {
+    let destinationStart = contentStart;
+    while (text[destinationStart] === ' ' || text[destinationStart] === '\	') destinationStart++;
+    let close = destinationStart + 1;
+    for (; close < text.length; close++) {
+      if (text[close] === '\\\') close++;
+      else if (text[close] === '>') break;
+    }
+    if (close >= text.length) return null;
+    end = close + 1;
+    while (text[end] === ' ' || text[end] === '\	') end++;
+    if (text[end] !== ')') return null; // A title or other syntax is intentionally unsupported.
+    target = text.slice(destinationStart + 1, close);
+  } else {
+    let parenDepth = 0;
+    let destinationEnd = contentStart;
+    for (; destinationEnd < text.length; destinationEnd++) {
+      const character = text[destinationEnd];
+      if (character === '\\\') {
+        destinationEnd++;
+      } else if (character === '(') {
+        parenDepth++;
+      } else if (character === ')') {
+        if (parenDepth === 0) break;
+        parenDepth--;
+      } else if (character === '\
' || character === '\\r') {
+        return null;
+      } else if ((character === ' ' || character === '\	') && parenDepth === 0) {
+        break;
+      }
+    }
+    if (destinationEnd >= text.length) return null;
+    target = text.slice(contentStart, destinationEnd);
+    end = destinationEnd;
+    while (text[end] === ' ' || text[end] === '\	') end++;
+    if (text[end] !== ')') return null; // This includes links with titles.
+  }
+
+  const syntax = text.slice(start, end + 1);
+  if (syntax.includes('\
') || syntax.includes('\\r')) return null;
+  return {end: end + 1, image, label: unescapeMarkdown(label), target: unescapeMarkdown(target)};
+}
+
+function markdownToWiki(text: string, convertLinks: boolean, convertImages: boolean): string {
+  let output = '';
+  let index = 0;
+  while (index < text.length) {
+    const candidate = text[index] === '[' || (text[index] === '!' && text[index + 1] === '[');
+    if (!candidate) {
+      output += text[index++];
+      continue;
+    }
+    const link = parseMarkdownLink(text, index);
+    if (!link || link.target.includes('://') || (link.image ? !convertImages : !convertLinks)) {
+      output += text[index++];
+      continue;
+    }
+    if (link.image) {
+      output += `![[${link.target}${link.label && link.label !== link.target ? `|${link.label}` : ''}]]`;
+    } else {
+      const defaultDisplay = defaultHeadingDisplay(link.target);
+      output += `[[${link.target}${link.label !== link.target && link.label !== defaultDisplay ? `|${link.label}` : ''}]]`;
+    }
+    index = link.end;
+  }
+  return output;
+}
